#-------------------------------------------------------------------------------
# sim_study_lognormal_width_sd.R
#
# Simulation study validating recovery of the log-scale pulse-width SD
# (sigma_width) -- and pulse-mass SD (sigma_mass) -- under the papers-default
# single-subject fit {lognormal random effects, Uniform(0, .) SD prior,
# Gaussian pulses (kappa fixed at 1)}.
#
# Data are generated by simulate_pulse(pulse_distribution = "lognormal"), whose
# mass_mean / mass_sd / width_mean / width_sd are LOG-scale parameters, exactly
# matching the fit parameterization: pulse width = exp(N(mu_width, sigma_width^2)).
#
# This directory is .Rbuildignore'd, so nothing here affects R CMD check.
#
# Usage:  cd R-package && Rscript benchmarks/sim_study_lognormal_width_sd.R
#-------------------------------------------------------------------------------

# Locate the R-package root (this file lives in R-package/benchmarks/). Works
# whether invoked from R-package/ or R-package/benchmarks/.
.pkg_root <- if (file.exists("DESCRIPTION")) "." else
  if (file.exists("../DESCRIPTION")) ".." else
    stop("Run from the R-package directory: Rscript benchmarks/sim_study_lognormal_width_sd.R")
suppressMessages(devtools::load_all(.pkg_root))

# --- true log-scale generating parameters -------------------------------------
TRUTH <- list(
  mu_mass     = 1.2,   # mean log-mass
  sigma_mass  = 0.5,   # SD of log-mass  (target of recovery)
  mu_width    = 3.0,   # mean log-width
  sigma_width = 0.5,   # SD of log-width (primary target of recovery)
  halflife    = 45,
  baseline    = 2.6,
  error_var   = 0.005
)

# Study size chosen for identifiability vs. runtime. num_obs = 240 (40 h at a
# 10-min sampling interval) yields ~20 pulses -- enough pulse-to-pulse width
# observations to identify sigma_width, while keeping the fit to ~15-20 min.
# (Runtime scales steeply with pulse count: the birth-death recomputes partial
# likelihoods O(n_pulses) per event.)
SEED   <- 20260706L
NUMOBS <- 240L
INTERVAL <- 10L
IPI_MEAN <- 12
ITERS  <- 60000L
THIN   <- 20L
BURNIN <- 20000L

# --- effective sample size (batch-means / autocorrelation, no extra deps) -----
ess <- function(x) {
  x <- x[is.finite(x)]
  n <- length(x)
  if (n < 10 || stats::sd(x) == 0) return(NA_real_)
  ac <- stats::acf(x, lag.max = min(n - 1, 200), plot = FALSE)$acf[-1]
  # sum autocorrelations up to first negative (initial positive sequence)
  k <- which(ac < 0)[1]
  if (is.na(k)) k <- length(ac)
  rho_sum <- if (k > 1) sum(ac[seq_len(k - 1)]) else 0
  n / (1 + 2 * rho_sum)
}

report_param <- function(name, draws, truth) {
  ci <- stats::quantile(draws, c(0.025, 0.975), names = FALSE)
  cover <- truth >= ci[1] && truth <= ci[2]
  cat(sprintf(
    "  %-12s truth=%.3f  post.mean=%.3f  95%% CI=[%.3f, %.3f]  covers=%s  ESS=%.0f\n",
    name, truth, mean(draws), ci[1], ci[2], cover, ess(draws)))
  invisible(list(mean = mean(draws), ci = ci, covers = cover, ess = ess(draws)))
}

# --- simulate lognormal-consistent single-subject data ------------------------
set.seed(SEED)
sim <- simulate_pulse(
  num_obs   = NUMOBS, interval = INTERVAL,
  ipi_mean  = IPI_MEAN,
  mass_mean = TRUTH$mu_mass,  mass_sd  = TRUTH$sigma_mass,
  width_mean = TRUTH$mu_width, width_sd = TRUTH$sigma_width,
  constant_halflife = TRUTH$halflife,
  constant_baseline = TRUTH$baseline,
  error_var = TRUTH$error_var,
  pulse_distribution = "lognormal")

np <- nrow(sim$parameters)
cat("=== Log-normal single-subject sim study =====================\n")
cat(sprintf("seed=%d  num_obs=%d (%.0f h)  simulated pulses=%d\n",
            SEED, NUMOBS, NUMOBS * INTERVAL / 60, np))
cat(sprintf("empirical log-width mean/sd = %.3f / %.3f  (truth %.2f / %.2f)\n",
            mean(log(sim$parameters$width)), stats::sd(log(sim$parameters$width)),
            TRUTH$mu_width, TRUTH$sigma_width))
cat(sprintf("empirical log-mass  mean/sd = %.3f / %.3f  (truth %.2f / %.2f)\n",
            mean(log(sim$parameters$mass)), stats::sd(log(sim$parameters$mass)),
            TRUTH$mu_mass, TRUTH$sigma_mass))

# --- fit with the papers-default spec (lognormal / uniform / gaussian) --------
spec <- pulse_spec(location_prior_type = "strauss",
                   prior_mean_pulse_count = np)

t0  <- Sys.time()
fit <- fit_pulse(data = sim, spec = spec,
                 iters = ITERS, thin = THIN, burnin = BURNIN, verbose = FALSE)
cat(sprintf("fit: %d iters, thin %d, burnin %d  (%.0f s, %d saved draws)\n\n",
            ITERS, THIN, BURNIN, as.numeric(Sys.time() - t0, units = "secs"),
            nrow(fit$patient_chain)))

pc <- fit$patient_chain
cat("Recovery (posterior vs. log-scale truth):\n")
r_wsd <- report_param("width_sd",   pc$width_sd,   TRUTH$sigma_width)
r_msd <- report_param("mass_sd",    pc$mass_sd,    TRUTH$sigma_mass)
report_param("width_mean",  pc$width_mean, TRUTH$mu_width)
report_param("mass_mean",   pc$mass_mean,  TRUTH$mu_mass)
cat(sprintf("  %-12s truth=%d    post.mean=%.2f\n",
            "num_pulses", np, mean(pc$num_pulses)))

cat("\nTrace health:\n")
cat(sprintf("  width_sd finite: %s   range=[%.3f, %.3f]\n",
            all(is.finite(pc$width_sd)), min(pc$width_sd), max(pc$width_sd)))
cat(sprintf("  mass_sd  finite: %s   range=[%.3f, %.3f]\n",
            all(is.finite(pc$mass_sd)), min(pc$mass_sd), max(pc$mass_sd)))
cat(sprintf("  width_sd hits prior bound (%.0f)? max/bound=%.2f\n",
            spec$priors$width_sd_max, max(pc$width_sd) / spec$priors$width_sd_max))

invisible(list(sim = sim, fit = fit, truth = TRUTH,
               width_sd = r_wsd, mass_sd = r_msd))
